(
  'Borscht',
  'Soup',
  'Ukrainian',
  'Heat oil in a large pot. Add diced onion and fry until golden. Add grated carrots and cook for 3 minutes. Add grated beetroot and cook for 5 minutes, stirring occasionally. Add diced potatoes and shredded cabbage. Pour in beef broth and bring to a boil. Reduce heat and simmer for 20 minutes until vegetables are tender. Add tomato paste, garlic, salt, pepper and bay leaves. Simmer for another 10 minutes. Remove from heat and let rest for 15 minutes. Serve hot with a dollop of sour cream and fresh dill.',
  NULL,
  '[{"ingredient": "beetroot", "measure": "2 pcs"}, {"ingredient": "cabbage", "measure": "300g"}, {"ingredient": "potatoes", "measure": "3 pcs"}, {"ingredient": "carrots", "measure": "2 pcs"}, {"ingredient": "onion", "measure": "1 pcs"}, {"ingredient": "beef broth", "measure": "2 liters"}, {"ingredient": "tomato paste", "measure": "2 tbsp"}, {"ingredient": "garlic", "measure": "3 cloves"}, {"ingredient": "sour cream", "measure": "for serving"}, {"ingredient": "fresh dill", "measure": "for garnish"}, {"ingredient": "bay leaves", "measure": "2 pcs"}, {"ingredient": "vegetable oil", "measure": "2 tbsp"}, {"ingredient": "salt and pepper", "measure": "to taste"}]',
